import { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import useCart from '../context/useCart';

const CHECKOUT_STORAGE_KEY = 'tienda_react_checkout_form';
const ORDERS_STORAGE_KEY = 'tienda_react_orders';

/**
 * Reads persisted checkout form values safely.
 * @returns {{ name: string, email: string, address: string, city: string, zip: string, card: string }}
 */
function getInitialCheckoutForm() {
  const fallback = {
    name: '',
    email: '',
    address: '',
    city: '',
    zip: '',
    card: '',
  };

  try {
    const rawForm = localStorage.getItem(CHECKOUT_STORAGE_KEY);
    return rawForm ? { ...fallback, ...JSON.parse(rawForm) } : fallback;
  } catch {
    return fallback;
  }
}

/**
 * Basic Luhn validation to reduce malformed card input before submission.
 * @param {string} cardNumber
 * @returns {boolean}
 */
function isValidCardLuhn(cardNumber) {
  let sum = 0;
  let shouldDouble = false;

  for (let i = cardNumber.length - 1; i >= 0; i -= 1) {
    let digit = Number.parseInt(cardNumber[i], 10);
    if (Number.isNaN(digit)) {
      return false;
    }

    if (shouldDouble) {
      digit *= 2;
      if (digit > 9) {
        digit -= 9;
      }
    }

    sum += digit;
    shouldDouble = !shouldDouble;
  }

  return sum % 10 === 0;
}

/**
 * Saves a completed order to local history.
 * @param {{ name: string }} formData
 * @param {Array<{ id: number|string, name: string, quantity: number, price: number }>} items
 * @param {number} total
 */
function persistOrder(formData, items, subtotal, discountAmount, finalPrice, coupon) {
  const newOrder = {
    id: `${Date.now()}`,
    createdAt: new Date().toISOString(),
    customerName: formData.name.trim(),
    totalItems: items.reduce((sum, item) => sum + item.quantity, 0),
    subtotalPrice: subtotal,
    discountAmount,
    couponCode: coupon?.code ?? null,
    totalPrice: finalPrice,
    items: items.map((item) => ({
      id: item.id,
      name: item.name,
      quantity: item.quantity,
      price: item.price,
      image: item.image,
    })),
  };

  try {
    const rawOrders = localStorage.getItem(ORDERS_STORAGE_KEY);
    const currentOrders = rawOrders ? JSON.parse(rawOrders) : [];
    const safeOrders = Array.isArray(currentOrders) ? currentOrders : [];
    localStorage.setItem(ORDERS_STORAGE_KEY, JSON.stringify([newOrder, ...safeOrders]));
  } catch {
    localStorage.setItem(ORDERS_STORAGE_KEY, JSON.stringify([newOrder]));
  }
}

/**
 * Reusable field used by checkout form sections.
 */
function CheckoutField({
  id,
  label,
  type = 'text',
  name,
  placeholder,
  autoComplete,
  inputMode,
  maxLength,
  value,
  hasError,
  errorMessage,
  onChange,
}) {
  return (
    <div className="flex flex-col gap-1">
      <label htmlFor={id} className="text-sm font-medium text-gray-700">
        {label}
      </label>
      <input
        id={id}
        type={type}
        name={name}
        value={value}
        onChange={onChange}
        placeholder={placeholder}
        autoComplete={autoComplete}
        inputMode={inputMode}
        maxLength={maxLength}
        className={`border rounded-lg px-3 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition ${
          hasError ? 'border-red-400' : 'border-gray-300'
        }`}
        aria-invalid={hasError}
        aria-describedby={hasError ? `${id}-error` : undefined}
      />
      {hasError && (
        <span id={`${id}-error`} className="text-red-500 text-xs" role="alert">
          {errorMessage}
        </span>
      )}
    </div>
  );
}

/**
 * Checkout page with a simple order form.
 * On submission it clears the cart and redirects to a confirmation page.
 * Input validation happens on the client boundary.
 */
export default function Checkout() {
  const { cart, totalPrice, discountAmount, finalPrice, coupon, dispatch, showToast } = useCart();
  const navigate = useNavigate();

  const [form, setForm] = useState(getInitialCheckoutForm);
  const [errors, setErrors] = useState({});
  const [submitted, setSubmitted] = useState(false);

  useEffect(() => {
    localStorage.setItem(CHECKOUT_STORAGE_KEY, JSON.stringify(form));
  }, [form]);

  const validate = () => {
    const newErrors = {};
    if (!form.name.trim()) newErrors.name = 'El nombre es obligatorio.';
    if (!form.email.trim() || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(form.email)) {
      newErrors.email = 'Ingresa un correo válido.';
    }
    if (!form.address.trim()) newErrors.address = 'La dirección es obligatoria.';
    if (!form.city.trim()) newErrors.city = 'La ciudad es obligatoria.';
    if (!form.zip.trim() || !/^\d{4,10}$/.test(form.zip)) {
      newErrors.zip = 'Código postal inválido (4-10 dígitos).';
    }
    const normalizedCard = form.card.replace(/\s/g, '');
    if (!/^\d{16}$/.test(normalizedCard) || !isValidCardLuhn(normalizedCard)) {
      newErrors.card = 'Número de tarjeta inválido.';
    }
    return newErrors;
  };

  const handleChange = (e) => {
    const { name, value } = e.target;
    const nextValue = name === 'card' ? value.replace(/[^\d\s]/g, '').slice(0, 19) : value;
    setForm((prev) => ({ ...prev, [name]: nextValue }));
    if (errors[name]) setErrors((prev) => ({ ...prev, [name]: undefined }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    const validationErrors = validate();
    if (Object.keys(validationErrors).length > 0) {
      setErrors(validationErrors);
      return;
    }

    persistOrder(form, cart, totalPrice, discountAmount, finalPrice, coupon);
    setSubmitted(true);
    dispatch({ type: 'CLEAR_CART' });
    localStorage.removeItem(CHECKOUT_STORAGE_KEY);
    showToast('Pedido confirmado correctamente', 'success');
    setTimeout(() => navigate('/pedidos'), 2200);
  };

  if (cart.length === 0 && !submitted) {
    return (
      <main className="max-w-xl mx-auto px-4 py-16 text-center">
        <p className="text-5xl mb-4" aria-hidden="true">🛒</p>
        <h1 className="text-2xl font-bold text-gray-800 mb-2">No hay productos en el carrito</h1>
        <Link to="/" className="text-indigo-600 underline">Volver a la tienda</Link>
      </main>
    );
  }

  if (submitted) {
    return (
      <main className="max-w-xl mx-auto px-4 py-20 text-center" role="status" aria-live="polite">
        <p className="text-6xl mb-4" aria-hidden="true">✅</p>
        <h1 className="text-2xl font-bold text-gray-800 mb-2">¡Pedido confirmado!</h1>
        <p className="text-gray-500 mb-5">Gracias por tu compra. Serás redirigido al historial de pedidos.</p>
        <Link
          to="/pedidos"
          className="inline-block rounded-xl bg-indigo-600 px-5 py-2.5 font-medium text-white transition hover:bg-indigo-700 focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
        >
          Ver mis pedidos
        </Link>
      </main>
    );
  }

  return (
    <main className="max-w-4xl mx-auto px-4 py-8">
      <h1 className="text-3xl font-bold text-gray-900 mb-8">Finalizar compra</h1>

      <div className="flex flex-col lg:flex-row gap-8">
        {/* Form */}
        <section className="flex-1" aria-label="Formulario de envío y pago">
          <form onSubmit={handleSubmit} noValidate className="flex flex-col gap-5">
            <fieldset className="flex flex-col gap-4">
              <legend className="font-semibold text-gray-800 text-base mb-1">Datos personales</legend>
              <CheckoutField id="name" label="Nombre completo" name="name" placeholder="Ana García" autoComplete="name" value={form.name} hasError={!!errors.name} errorMessage={errors.name} onChange={handleChange} />
              <CheckoutField id="email" label="Correo electrónico" name="email" type="email" placeholder="ana@correo.com" autoComplete="email" value={form.email} hasError={!!errors.email} errorMessage={errors.email} onChange={handleChange} />
            </fieldset>

            <fieldset className="flex flex-col gap-4">
              <legend className="font-semibold text-gray-800 text-base mb-1">Dirección de envío</legend>
              <CheckoutField id="address" label="Calle y número" name="address" placeholder="Av. Libertad 1234" autoComplete="street-address" value={form.address} hasError={!!errors.address} errorMessage={errors.address} onChange={handleChange} />
              <div className="grid grid-cols-2 gap-4">
                <CheckoutField id="city" label="Ciudad" name="city" placeholder="Buenos Aires" autoComplete="address-level2" value={form.city} hasError={!!errors.city} errorMessage={errors.city} onChange={handleChange} />
                <CheckoutField id="zip" label="Código postal" name="zip" placeholder="1425" autoComplete="postal-code" value={form.zip} hasError={!!errors.zip} errorMessage={errors.zip} onChange={handleChange} />
              </div>
            </fieldset>

            <fieldset className="flex flex-col gap-4">
              <legend className="font-semibold text-gray-800 text-base mb-1">Pago</legend>
              <CheckoutField
                id="card"
                label="Número de tarjeta"
                name="card"
                placeholder="1234 5678 9012 3456"
                autoComplete="cc-number"
                inputMode="numeric"
                maxLength={19}
                value={form.card}
                hasError={!!errors.card}
                errorMessage={errors.card}
                onChange={handleChange}
              />
            </fieldset>

            <button
              type="submit"
              className="mt-2 bg-indigo-600 hover:bg-indigo-700 active:scale-95 text-white font-semibold px-4 py-3 rounded-xl transition focus-visible:outline-2 focus-visible:outline-offset-2 focus-visible:outline-indigo-600"
            >
              Confirmar pedido — ${finalPrice.toFixed(2)}
            </button>
          </form>
        </section>

        {/* Order summary */}
        <aside className="lg:w-72" aria-label="Resumen del pedido">
          <div className="bg-white rounded-2xl shadow p-6 sticky top-24">
            <h2 className="font-bold text-gray-800 text-base mb-4">Tu pedido</h2>
            <ul className="flex flex-col gap-3 mb-4" role="list">
              {cart.map((item) => (
                <li key={item.id} className="flex items-center gap-3">
                  <img
                    src={item.image}
                    alt={item.name}
                    className="w-12 h-12 rounded-lg object-cover flex-shrink-0"
                  />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-gray-800 truncate">{item.name}</p>
                    <p className="text-xs text-gray-500">x{item.quantity}</p>
                  </div>
                  <span className="text-sm font-semibold text-gray-900">
                    ${(item.price * item.quantity).toFixed(2)}
                  </span>
                </li>
              ))}
            </ul>
            <dl className="flex flex-col gap-1 text-sm text-gray-600 border-t pt-3">
              <div className="flex justify-between">
                <dt>Subtotal</dt>
                <dd className="font-medium">${totalPrice.toFixed(2)}</dd>
              </div>
              {discountAmount > 0 && (
                <div className="flex justify-between">
                  <dt className="text-green-700">Descuento ({coupon?.code})</dt>
                  <dd className="font-medium text-green-700">−${discountAmount.toFixed(2)}</dd>
                </div>
              )}
              <div className="flex justify-between">
                <dt>Envío</dt>
                <dd className="text-green-600 font-medium">Gratis</dd>
              </div>
            </dl>
            <div className="mt-2 flex justify-between font-bold text-gray-900">
              <span>Total</span>
              <span>${finalPrice.toFixed(2)}</span>
            </div>
          </div>
        </aside>
      </div>
    </main>
  );
}
